parameters.jsCode:
// IRON DOME VIBE CHECK PROTOCOL (v2.0)

// 1. Get the text from the AI Agent
const generatedText =
  $input.item.json.output ||
  $input.item.json.text ||
  "";

// 2. Define the rules
const constraints = {
  forbidden_words: [
    "synergy",
    "blast",
    "skyrocket",
    "guaranteed",
    "100%",
    "crypto",
    "investment"
  ],
  copyright_risks: [
    "disney",
    "marvel",
    "star wars",
    "mickey mouse",
    "nike",
    "nintendo"
  ]
};

// 3. Scan the text
let violations = [];
const textLower = generatedText.toLowerCase();

// Scan for forbidden words
for (const word of constraints.forbidden_words) {
  if (textLower.includes(word.toLowerCase())) {
    violations.push(`Forbidden Word: "${word}"`);
  }
}

// Scan for copyright risks
for (const brand of constraints.copyright_risks) {
  if (textLower.includes(brand)) {
    violations.push(`Copyright Risk: "${brand}"`);
  }
}

// 4. Decision logic
const hasViolations = violations.length > 0;

// 5. Build base payload (keep everything that came in)
const base = {
  ...$json,
  generatedText
};

if (hasViolations) {
  // REJECT
  return {
    json: {
      ...base,
      status: "REJECTED",
      reason: violations.join(", "),
      original_text: generatedText,
      vibeCheck: {
        approved: false,
        violations
      }
    }
  };
} else {
  // APPROVE
  return {
    json: {
      ...base,
      status: "APPROVED",
      final_text: generatedText,
      timestamp: new Date().toISOString(),
      vibeCheck: {
        approved: true,
        violations: []
      }
    }
  };
}

